module innerA(output [7:0] a_out, input clk); assign a_out = 8'hAB; endmodule
module innerB(output [7:0] b_out, input [7:0] b_in); assign b_out = b_in; endmodule
module innerC(output [7:0] c_out, input [7:0] c_in); assign c_out = c_in; endmodule
module top(output [7:0] result, input clk);
  wire [7:0] wire1, wire2;
  innerA ia(.a_out(wire1), .clk(clk));
  innerB ib(.b_out(wire2), .b_in(wire1));
  innerC ic(.c_out(result), .c_in(wire2));
endmodule

module cpu(output [15:0] out, input clk, input reset);
  logic [15:0] reg_val;
  always_ff @(posedge clk) begin
    if (reset) reg_val <= 16'b0;
    else reg_val <= reg_val + 16'b1;
  end
  assign out = reg_val;
endmodule
